464→func run() error {
465→	cliInit()
466→
467→	if flagVersion {
468→		printVersion()
469→		return nil
470→	}
471→
472→	// Initialize logger
473→	cclog.Init(flagLogLevel, flagLogDateTime)
474→
475→	// Handle init flag
476→	if flagInit {
477→		initEnv()
478→		cclog.Exit("Successfully setup environment!\n" +
479→			"Please review config.json and .env and adjust it to your needs.\n" +
480→			"Add your job-archive at ./var/job-archive.")
481→	}
482→
483→	// Initialize gops agent
484→	if err := initGops(); err != nil {
485→		return err
486→	}
487→
488→	// Initialize subsystems in dependency order:
489→	// 1. Load environment variables from .env file (contains sensitive configuration)
490→	// 2. Load configuration from config.json (may reference environment variables)
491→	// 3. Handle database migration commands if requested
492→	// 4. Initialize database connection (requires config for connection string)
493→	// 5. Handle user commands if requested (requires database and authentication config)
494→	// 6. Initialize subsystems like archive and metrics (require config and database)
495→
496→	// Load environment and configuration
497→	if err := loadEnvironment(); err != nil {
498→		return err
499→	}
500→
501→	if err := initConfiguration(); err != nil {
502→		return err
503→	}
504→
505→	// Handle database migration (migrate, revert, force)
506→	if err := handleDatabaseCommands(); err != nil {
507→		return err
508→	}
509→
510→	// Initialize database
511→	if err := initDatabase(); err != nil {
512→		return err
513→	}
514→
515→	// Optimize database if requested
516→	if flagOptimizeDB {
517→		db := repository.GetConnection()
518→		cclog.Print("Running VACUUM to reclaim space and defragment database...")
519→		if _, err := db.DB.Exec("VACUUM"); err != nil {
520→			return fmt.Errorf("VACUUM failed: %w", err)
521→		}
522→		cclog.Print("Running ANALYZE to update query planner statistics...")
523→		if _, err := db.DB.Exec("ANALYZE"); err != nil {
524→			return fmt.Errorf("ANALYZE failed: %w", err)
525→		}
526→		cclog.Exitf("OptimizeDB Success: Database '%s' optimized (VACUUM + ANALYZE).\n", config.Keys.DB)
527→	}
528→
529→	// Handle user commands (add, delete, sync, JWT)
530→	if err := handleUserCommands(); err != nil {
531→		return err
532→	}
533→
534→	// Initialize subsystems (archive, metrics, taggers)
535→	if err := initSubsystems(); err != nil {
536→		return err
537→	}
538→
539→	// Exit if start server is not requested
540→	if !flagServer {
541→		cclog.Exit("No errors, server flag not set. Exiting cc-backend.")
542→	}
543→
544→	// Run server with context
545→	ctx, cancel := context.WithCancel(context.Background())
546→	defer cancel()
547→
548→	return runServer(ctx)
549→}
